<script setup lang="ts">
import { computed } from 'vue';
import { useRouter } from 'vue-router';
import type { AgentInfo, SkillDetail, SkillInfo } from '../../api';
import AgentStack from './AgentStack.vue';

const props = defineProps<{ skill: SkillInfo | null; detail: SkillDetail | null; agents: AgentInfo[]; loading?: boolean }>();
const emit = defineEmits<{ close: []; distribute: [skill: SkillInfo] }>();
const router = useRouter();
const source = computed(() => {
  const item = props.detail?.skill.source;
  if (!item) return '正在读取来源…';
  return item.type === 'github' ? [item.owner, item.repo, item.skillPath].filter(Boolean).join('/') : '本地来源';
});
function openDetails() { if (props.skill) router.push({ name: 'skillDetail', params: { name: props.skill.name } }); }
</script>

<template>
  <aside :class="['skill-inspector', skill && 'skill-inspector--open']" aria-label="Skill 检查器">
    <template v-if="skill"><header><div class="min-w-0"><p>INSPECTOR</p><h2>{{ skill.name }}</h2></div><button type="button" aria-label="关闭检查器" @click="emit('close')">×</button></header><div class="inspector-scroll"><section class="inspector-status"><span :class="skill.managed ? 'status-dot status-dot--ok' : 'status-dot status-dot--warning'" /><div><b>{{ skill.managed ? '受 SkillSync 管理' : '需要关联来源' }}</b><small>{{ skill.agents.length ? `已分发至 ${skill.agents.length} 个 Agent` : '还没有分发目标' }}</small></div></section><section><p class="section-label">来源</p><p class="source-value">{{ source }}</p><p v-if="detail?.skill.source?.commit" class="source-commit">{{ detail.skill.source.commit.slice(0, 10) }}</p></section><section><p class="section-label">当前版本</p><div class="version-line"><b>v{{ skill.version }}</b><span>{{ detail?.skill.updatedAt ? `更新于 ${new Date(detail.skill.updatedAt).toLocaleDateString()}` : '等待详情' }}</span></div></section><section><div class="section-row"><p class="section-label">分发</p><span>{{ skill.agents.length }} / {{ agents.filter(agent => agent.installed).length }}</span></div><div v-if="skill.agents.length" class="distribution-list"><div v-for="agent in skill.agents" :key="agent" class="distribution-item"><span><i class="status-dot status-dot--ok" />{{ agents.find(item => item.name === agent)?.displayName ?? agent }}</span><small>已覆盖</small></div></div><button v-else class="empty-distribution" type="button" @click="emit('distribute', skill)">添加第一个分发目标</button><AgentStack v-if="skill.agents.length" :agent-names="skill.agents" :agents="agents" /></section><section v-if="detail?.skill.dependencies?.length"><p class="section-label">依赖</p><p class="dependency-copy">{{ detail.skill.dependencies.length }} 项声明依赖，更新前可在详情页审查。</p></section></div><footer><button class="inspector-secondary" type="button" @click="openDetails">完整详情</button><button class="inspector-primary" type="button" @click="emit('distribute', skill)">{{ skill.agents.length ? '管理分发' : '开始分发' }}</button></footer></template>
    <div v-else class="inspector-empty"><span>⌘</span><b>选择一个 Skill</b><p>在卡片上点击后，可在这里查看来源、版本与分发状态。</p></div>
  </aside>
</template>

<style scoped>
